"use client";
import React from "react";

export default function LeftPanel() {
  return (
    <div className="d-flex flex-column h-100">
      {/* Barre de recherche */}
      <div className="d-flex mb-3 shadow-sm" style={{ width: "350px" }}>
        <div
          className="d-flex align-items-center justify-content-center"
          style={{ width: "40px", backgroundColor: "#f09c13" }}
        >
          <span className="text-dark fw-bold">Q</span>
        </div>
        <input
          type="text"
          className="form-control rounded-0"
          defaultValue="Raysquad#2902"
          style={{
            backgroundColor: "#e9ecef",
            borderColor: "#f09c13",
            borderWidth: "2px",
            borderLeft: "none",
          }}
        />
      </div>

      {/* En-tête : Bannière + PP + Pseudo */}
      <div
        className="mb-0 position-relative"
        style={{ height: "150px", width: "350px" }}
      >
        {/* Bannière inversée */}
        <div
          className="position-absolute top-0 start-0 bg-dark"
          style={{
            width: "410px",
            height: "150px",
            backgroundImage:
              "url(https://blz-contentstack-images.akamaized.net/v3/assets/blt2477dcaf4ebd440c/blt4bb4c31f6849c25b/631a8b781613910e6926bfd4/2600_Cassidy.jpg)",
            backgroundSize: "cover",
            backgroundPosition: "center",
            transform: "scaleX(-1)",
            borderRight: "6px solid #f09c13",
            zIndex: 1,
          }}
        ></div>

        {/* Avatar placé à cheval sur la ligne de démarcation (350px) */}
        <div
          className="bg-white p-1 position-absolute"
          style={{
            width: "100px",
            height: "100px",
            transform: "scaleX(-1)",
            border: "3px solid #f09c13",
            left: "370px",
            top: "25px",
            zIndex: 2,
          }}
        >
          <img
            src="https://d15f34w2p8l1cc.cloudfront.net/overwatch/9240cd64cc8ef58df9acbf55204ab1b5d8578f743fda5931f0dbccbd75ab841b.png"
            alt="Avatar"
            className="w-100 h-100 object-fit-cover"
          />
        </div>

        {/* Pseudo décalé à droite de l'avatar */}
        <div
          className="fw-bold fs-3 text-dark text-nowrap position-absolute"
          style={{
            zIndex: 2,
            left: "490px",
            top: "42px",
          }}
        >
          Raysquad
        </div>
      </div>

      {/* Contenu principal (bloc blanc) */}
      <div
        className="bg-white d-flex flex-column pt-4 pb-3 shadow-sm"
        style={{ width: "350px", flexGrow: 1 }}
      >
        {/* Info Héros Sélectionné */}
        <div className="d-flex align-items-center mb-3 px-3">
          <div
            className="bg-white p-1 me-3"
            style={{
              width: "90px",
              height: "90px",
              transform: "scaleX(-1)",
              border: "2px solid #f09c13",
            }}
          >
            <img
              src="https://d15f34w2p8l1cc.cloudfront.net/overwatch/9240cd64cc8ef58df9acbf55204ab1b5d8578f743fda5931f0dbccbd75ab841b.png"
              alt="Cassidy"
              className="w-100 h-100 object-fit-cover"
            />
          </div>
          <div>
            <div
              className="fw-bold text-uppercase"
              style={{ fontSize: "1rem", color: "#f09c13" }}
            >
              Damage
            </div>
            <div
              className="fw-bold fs-3 text-uppercase text-dark"
              style={{ lineHeight: "1" }}
            >
              CASSIDY
            </div>
          </div>
        </div>

        {/* Grille de sélection des héros */}
        <div className="px-3 mb-auto mt-2" style={{ maxWidth: "240px" }}>
          <button
            className="btn w-100 d-flex justify-content-between align-items-center rounded-0 fw-bold mb-2 border-0"
            style={{
              backgroundColor: "#d0d5d9",
              color: "#333",
              border: "2px solid #A8ABB4",
            }}
          >
            SELECT HERO
            <span style={{ fontSize: "0.8rem" }}>▲</span>
          </button>
          <div
            className="d-flex flex-wrap border rounded p-1 bg-white"
            style={{ gap: "2px" }}
          >
            {Array.from({ length: 12 }).map((_, i) => (
              <div
                key={i}
                style={{
                  width: "calc(25% - 1.5px)",
                  aspectRatio: "1/1",
                  transform: "scaleX(-1)",
                  border: i === 0 ? "2px solid #f09c13" : "1px solid #dee2e6",
                }}
              >
                <img
                  src="https://d15f34w2p8l1cc.cloudfront.net/overwatch/9240cd64cc8ef58df9acbf55204ab1b5d8578f743fda5931f0dbccbd75ab841b.png"
                  alt={`hero-${i}`}
                  className="w-100 h-100 object-fit-cover"
                />
              </div>
            ))}
          </div>
        </div>

        {/* Rang */}
        <div className="d-flex align-items-center px-3 mt-4">
          <div
            className="rounded-circle d-flex justify-content-center align-items-center fw-bold fs-3 me-3 text-dark"
            style={{
              width: "80px",
              height: "80px",
              border: "4px solid #f09c13",
            }}
          >
            88
          </div>
          <div>
            <div
              className="fw-bold"
              style={{ fontSize: "0.9rem", color: "#cdd3d8" }}
            >
              Overall
            </div>
            <div className="fw-bold fs-4 text-uppercase text-dark">MASTER</div>
          </div>
        </div>
      </div>
    </div>
  );
}
